import React, { useState } from "react";
import VideoPanel from "../components/videoPanel";
import BarraHorizontal from "../components/barraHorizontal";
import ContenedorLateral from "../components/contenedorLateral";
import ContenedorImagenes from "../components/contenedorImagenes";
import MapaBolivia from "../components/mapaBolivia";
import ImagenInteractiva from "../components/imagenInteractiva";
import CarruselImagenes from "../components/carruselImagenes";
import DashboardPanel from "../components/dashbordPanel";
import AnadirPropietario from "../components/anadirpropietario";
import AnadirSede from "../components/anadirsede";
import AnadirItem from "../components/anadiritem";
import AnadirUsuario from "../components/anadirusuario";


const HomePage = () => {
  const [mostrarModal, setMostrarModal] = useState(false);
  const [empresaSeleccionada, setEmpresaSeleccionada] = useState("");

  // Nuevo estado para modales personalizados
  const [modalAbierto, setModalAbierto] = useState("");

  const abrirModal = (empresa) => {
    setEmpresaSeleccionada(empresa);
    setMostrarModal(true);
  };

  const cerrarModal = () => {
    setMostrarModal(false);
    setEmpresaSeleccionada("");
  };

  const cerrarModalPersonalizado = () => {
    setModalAbierto("");
  };

  return (
    <div className="w-full min-h-screen flex flex-col gap-8 relative">
      <VideoPanel height="60vh">
        <video src="/media/homePage/video.webm" autoPlay muted loop />
      </VideoPanel>

      <BarraHorizontal
        texto="¡Bienvenidos a nuestra página!"
        height="3vh"
        margenHorizontal="30vw"
        imagen="/media/homePage/barra.png"
      />

      <div className="w-full flex justify-start items-start gap-[0vw] px-[0vw]">
        <div className="mt-[10vh]">
          <ImagenInteractiva
            ancho="40vw"
            imagenDefault="/media/homePage/defaultImage.png"
            items={[
              {
                icono: "/media/homePage/lightIcon.png",
                subtitulo: "Primera Selección",
                imagen: "/media/contenido/contenido1.png",
                texto: "Este es el contenido relacionado al primer ícono.",
              },
              {
                icono: "/media/homePage/recicleIcon.png",
                subtitulo: "Segunda Selección",
                imagen: "/media/contenido/contenido2.png",
                texto: "Información para el segundo ícono seleccionada.",
              },
              {
                icono: "/media/homePage/secureIcon.png",
                subtitulo: "Tercera Selección",
                imagen: "/media/contenido/contenido3.png",
                texto: "Texto descriptivo para el tercer ícono.",
              },
              {
                icono: "/media/homePage/awardIcon.png",
                subtitulo: "Tercera Selección",
                imagen: "/media/contenido/contenido3.png",
                texto: "Texto descriptivo para el tercer ícono.",
              },
            ]}
          />
      </div>

        <ContenedorLateral
          subtitulo="Novedades"
          texto="Explorá las últimas noticias, actualizaciones y promociones disponibles en nuestra plataforma."
          imagen="/media/homePage/lateral.png"
          ancho="70vw"
          alto="80vh"
          ovaloRedondez="20px"
          cuadroRedondez="10px"
        />
      </div>

      
      <BarraHorizontal
        texto="EMPRESAS CON RECORRIDO DE +500 AÑOS"
        height="3vh"
        margenHorizontal="30vw"
        imagen="/media/homePage/barra.png"
      />



      <CarruselImagenes
        altura={400}
        filas={3}
        backendUrl="http://localhost:3000"
        modoPrueba={true}
      />

<div className="w-full flex justify-center gap-4 p-8">
        <button
          className="bg-blue-500 hover:bg-blue-600 text-white px-4 py-2 rounded"
          onClick={() => setModalAbierto("propietario")}
        >
          Añadir propietario
        </button>
        <button
          className="bg-green-500 hover:bg-green-600 text-white px-4 py-2 rounded"
          onClick={() => setModalAbierto("sede")}
        >
          Añadir sede
        </button>
        <button
          className="bg-yellow-500 hover:bg-yellow-600 text-white px-4 py-2 rounded"
          onClick={() => setModalAbierto("item")}
        >
          Añadir ítem
        </button>
        <button
          className="bg-purple-500 hover:bg-purple-600 text-white px-4 py-2 rounded"
          onClick={() => setModalAbierto("usuario")}
        >
          Añadir usuario
        </button>
      </div>

      {/* Modal Dashboard */}
      {mostrarModal && (
        <div className="fixed inset-0 bg-black bg-opacity-50 z-50 flex items-center justify-center">
          <div className="bg-white w-11/12 md:w-4/5 h-4/5 rounded-lg shadow-lg relative overflow-auto p-4">
            <DashboardPanel
              onClose={cerrarModal}
              tituloEmpresa={empresaSeleccionada}
            />
          </div>
        </div>
      )}

      {/* Modal Personalizado */}
      {modalAbierto && (
        <div className="fixed inset-0 bg-black bg-opacity-50 z-50 flex items-center justify-center">
          <div className="bg-white w-11/12 md:w-3/4 h-4/5 rounded-lg shadow-lg relative p-4 overflow-auto">
            <button
              className="absolute top-2 right-2 text-xl font-bold text-gray-600 hover:text-black"
              onClick={cerrarModalPersonalizado}
            >
              ×
            </button>
            {modalAbierto === "propietario" && <AnadirPropietario />}
            {modalAbierto === "sede" && <AnadirSede />}
            {modalAbierto === "item" && <AnadirItem />}
            {modalAbierto === "usuario" && <AnadirUsuario />}
          </div>
        </div>
      )}
    </div>

  );
};

export default HomePage;
